import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import { CssBaseline, Box } from '@mui/material';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import PostureAnalysis from './pages/PostureAnalysis';
import RiskAssessment from './pages/RiskAssessment';
import Rehabilitation from './pages/Rehabilitation';
import Settings from './pages/Settings';

const App = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const theme = createTheme({
    palette: {
      mode: darkMode ? 'dark' : 'light',
      primary: {
        main: '#8B5CF6',
        light: '#A78BFA',
        dark: '#7C3AED',
        contrastText: '#FFFFFF',
      },
      secondary: {
        main: '#EC4899',
        light: '#F472B6',
        dark: '#DB2777',
        contrastText: '#FFFFFF',
      },
      background: {
        default: darkMode ? '#0F0F23' : '#FAFBFC',
        paper: darkMode ? '#1A1B3A' : '#FFFFFF',
      },
      text: {
        primary: darkMode ? '#F1F5F9' : '#1E293B',
        secondary: darkMode ? '#94A3B8' : '#64748B',
      },
      divider: darkMode ? 'rgba(139, 92, 246, 0.12)' : 'rgba(124, 58, 237, 0.08)',
    },
    typography: {
      fontFamily: '"Poppins", "Roboto", "Helvetica", "Arial", sans-serif',
      h1: {
        fontFamily: '"Poppins", sans-serif',
        fontWeight: 800,
        fontSize: '3.5rem',
        lineHeight: 1.1,
        letterSpacing: '-0.02em',
        background: darkMode 
          ? 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)'
          : 'linear-gradient(135deg, #7C3AED 0%, #DB2777 100%)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
      },
      h4: {
        fontFamily: '"Poppins", sans-serif',
        fontWeight: 700,
        fontSize: '2.125rem',
        lineHeight: 1.2,
        letterSpacing: '-0.01em',
      },
      h5: {
        fontFamily: '"Poppins", sans-serif',
        fontWeight: 600,
        fontSize: '1.5rem',
        lineHeight: 1.3,
        letterSpacing: '-0.005em',
      },
      h6: {
        fontFamily: '"Poppins", sans-serif',
        fontWeight: 600,
        fontSize: '1.25rem',
        lineHeight: 1.4,
      },
      subtitle1: {
        fontFamily: '"Poppins", sans-serif',
        fontWeight: 500,
        fontSize: '1rem',
        lineHeight: 1.5,
      },
      body1: {
        fontFamily: '"Poppins", sans-serif',
        fontWeight: 400,
        fontSize: '0.875rem',
        lineHeight: 1.6,
      },
      body2: {
        fontFamily: '"Poppins", sans-serif',
        fontWeight: 400,
        fontSize: '0.75rem',
        lineHeight: 1.5,
      },
      caption: {
        fontFamily: '"JetBrains Mono", monospace',
        fontWeight: 500,
        fontSize: '0.75rem',
        lineHeight: 1.4,
        letterSpacing: '0.02em',
        textTransform: 'uppercase',
      },
      button: {
        fontFamily: '"Poppins", sans-serif',
        fontWeight: 600,
        fontSize: '0.875rem',
        textTransform: 'none',
        letterSpacing: '0.01em',
      },
    },
    spacing: 8,
    shape: {
      borderRadius: 16,
    },
    components: {
      MuiCssBaseline: {
        styleOverrides: {
          body: {
            scrollbarWidth: 'thin',
            scrollbarColor: darkMode ? '#8B5CF6 #1A1B3A' : '#8B5CF6 #F1F5F9',
            '&::-webkit-scrollbar': {
              width: 8,
            },
            '&::-webkit-scrollbar-track': {
              background: darkMode ? '#1A1B3A' : '#F1F5F9',
            },
            '&::-webkit-scrollbar-thumb': {
              background: 'linear-gradient(135deg, #8B5CF6, #EC4899)',
              borderRadius: 4,
            },
          },
        },
      },
      MuiCard: {
        styleOverrides: {
          root: {
            borderRadius: 20,
            background: darkMode 
              ? 'linear-gradient(145deg, rgba(26, 27, 58, 0.8) 0%, rgba(22, 23, 50, 0.8) 100%)'
              : 'linear-gradient(145deg, rgba(255, 255, 255, 0.9) 0%, rgba(248, 250, 252, 0.9) 100%)',
            border: darkMode 
              ? '1px solid rgba(139, 92, 246, 0.15)'
              : '1px solid rgba(124, 58, 237, 0.08)',
            boxShadow: darkMode
              ? '0 8px 32px rgba(0, 0, 0, 0.3), 0 0 0 1px rgba(139, 92, 246, 0.05)'
              : '0 8px 32px rgba(124, 58, 237, 0.08), 0 0 0 1px rgba(124, 58, 237, 0.03)',
            backdropFilter: 'blur(20px)',
            transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
            '&:hover': {
              transform: 'translateY(-4px)',
              boxShadow: darkMode
                ? '0 20px 40px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(139, 92, 246, 0.1)'
                : '0 20px 40px rgba(124, 58, 237, 0.12), 0 0 0 1px rgba(124, 58, 237, 0.06)',
            },
          },
        },
      },
      MuiCardContent: {
        styleOverrides: {
          root: {
            padding: '24px !important',
            '&:last-child': {
              paddingBottom: '24px !important',
            },
          },
        },
      },
      MuiButton: {
        styleOverrides: {
          root: {
            borderRadius: 12,
            textTransform: 'none',
            fontWeight: 600,
            fontSize: '0.875rem',
            padding: '12px 24px',
            minHeight: 44,
            transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
            position: 'relative',
            overflow: 'hidden',
            '&::before': {
              content: '""',
              position: 'absolute',
              top: 0,
              left: '-100%',
              width: '100%',
              height: '100%',
              background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent)',
              transition: 'left 0.5s',
            },
            '&:hover::before': {
              left: '100%',
            },
          },
          contained: {
            background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
            boxShadow: '0 4px 20px rgba(139, 92, 246, 0.3)',
            '&:hover': {
              background: 'linear-gradient(135deg, #7C3AED 0%, #DB2777 100%)',
              boxShadow: '0 8px 32px rgba(139, 92, 246, 0.4)',
              transform: 'translateY(-2px)',
            },
          },
          outlined: {
            border: '2px solid',
            borderImage: 'linear-gradient(135deg, #8B5CF6, #EC4899) 1',
            color: darkMode ? '#8B5CF6' : '#7C3AED',
            '&:hover': {
              background: 'rgba(139, 92, 246, 0.08)',
              borderImage: 'linear-gradient(135deg, #7C3AED, #DB2777) 1',
            },
          },
        },
      },
      MuiIconButton: {
        styleOverrides: {
          root: {
            borderRadius: 12,
            padding: 12,
            transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
            '&:hover': {
              transform: 'scale(1.05)',
            },
          },
        },
      },
      MuiAppBar: {
        styleOverrides: {
          root: {
            background: darkMode
              ? 'linear-gradient(135deg, rgba(15, 15, 35, 0.95) 0%, rgba(26, 27, 58, 0.95) 100%)'
              : 'linear-gradient(135deg, rgba(255, 255, 255, 0.95) 0%, rgba(250, 251, 252, 0.95) 100%)',
            backdropFilter: 'blur(20px)',
            borderBottom: darkMode
              ? '1px solid rgba(139, 92, 246, 0.15)'
              : '1px solid rgba(124, 58, 237, 0.08)',
            boxShadow: 'none',
          },
        },
      },
      MuiToolbar: {
        styleOverrides: {
          root: {
            minHeight: '80px !important',
            padding: '0 32px !important',
            '@media (max-width: 768px)': {
              padding: '0 16px !important',
            },
          },
        },
      },
      MuiDrawer: {
        styleOverrides: {
          paper: {
            background: darkMode
              ? 'linear-gradient(180deg, rgba(15, 15, 35, 0.95) 0%, rgba(26, 27, 58, 0.95) 100%)'
              : 'linear-gradient(180deg, rgba(255, 255, 255, 0.95) 0%, rgba(250, 251, 252, 0.95) 100%)',
            borderRight: darkMode
              ? '1px solid rgba(139, 92, 246, 0.15)'
              : '1px solid rgba(124, 58, 237, 0.08)',
            backdropFilter: 'blur(20px)',
          },
        },
      },
      MuiListItemButton: {
        styleOverrides: {
          root: {
            borderRadius: 16,
            margin: '4px 0',
            padding: '12px 16px',
            minHeight: 56,
            '&.Mui-selected': {
              background: 'linear-gradient(135deg, rgba(139, 92, 246, 0.15) 0%, rgba(236, 72, 153, 0.15) 100%)',
              border: '1px solid rgba(139, 92, 246, 0.3)',
              '&:hover': {
                background: 'linear-gradient(135deg, rgba(139, 92, 246, 0.2) 0%, rgba(236, 72, 153, 0.2) 100%)',
              },
            },
            '&:hover': {
              background: darkMode 
                ? 'rgba(139, 92, 246, 0.08)' 
                : 'rgba(124, 58, 237, 0.04)',
            },
          },
        },
      },
      MuiListItemIcon: {
        styleOverrides: {
          root: {
            minWidth: 48,
            marginRight: 12,
          },
        },
      },
      MuiListItemText: {
        styleOverrides: {
          primary: {
            fontFamily: '"Poppins", sans-serif',
            fontWeight: 500,
            fontSize: '0.875rem',
          },
        },
      },
      MuiLinearProgress: {
        styleOverrides: {
          root: {
            height: 8,
            borderRadius: 4,
            background: darkMode 
              ? 'rgba(139, 92, 246, 0.1)' 
              : 'rgba(124, 58, 237, 0.08)',
          },
          bar: {
            borderRadius: 4,
            background: 'linear-gradient(90deg, #8B5CF6 0%, #EC4899 100%)',
            boxShadow: '0 0 20px rgba(139, 92, 246, 0.4)',
          },
        },
      },
      MuiChip: {
        styleOverrides: {
          root: {
            borderRadius: 12,
            fontFamily: '"Poppins", sans-serif',
            fontWeight: 600,
            fontSize: '0.75rem',
            height: 32,
            backdropFilter: 'blur(10px)',
          },
          colorSuccess: {
            background: 'linear-gradient(135deg, #10B981 0%, #059669 100%)',
            color: '#FFFFFF',
            boxShadow: '0 4px 20px rgba(16, 185, 129, 0.3)',
          },
          colorWarning: {
            background: 'linear-gradient(135deg, #F59E0B 0%, #D97706 100%)',
            color: '#FFFFFF',
            boxShadow: '0 4px 20px rgba(245, 158, 11, 0.3)',
          },
          colorError: {
            background: 'linear-gradient(135deg, #EF4444 0%, #DC2626 100%)',
            color: '#FFFFFF',
            boxShadow: '0 4px 20px rgba(239, 68, 68, 0.3)',
          },
          colorPrimary: {
            background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
            color: '#FFFFFF',
            boxShadow: '0 4px 20px rgba(139, 92, 246, 0.3)',
          },
        },
      },
      MuiAvatar: {
        styleOverrides: {
          root: {
            fontFamily: '"Poppins", sans-serif',
            fontWeight: 600,
          },
        },
      },
      MuiTypography: {
        styleOverrides: {
          h1: {
            '@media (max-width: 768px)': {
              fontSize: '2.5rem',
            },
          },
          h4: {
            '@media (max-width: 768px)': {
              fontSize: '1.75rem',
            },
          },
          h5: {
            '@media (max-width: 768px)': {
              fontSize: '1.25rem',
            },
          },
        },
      },
      MuiGrid: {
        styleOverrides: {
          container: {
            margin: 0,
            width: '100%',
          },
          item: {
            paddingLeft: 0,
            paddingTop: 0,
          },
        },
      },
    },
  });

  const toggleDarkMode = () => {
    setDarkMode(!darkMode);
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <Router>
        <Box sx={{ display: 'flex' }}>
          <Navbar 
            darkMode={darkMode} 
            toggleDarkMode={toggleDarkMode}
            toggleSidebar={toggleSidebar}
          />
          <Sidebar open={sidebarOpen} />
          <Box
            component="main"
            sx={{
              flexGrow: 1,
              p: { xs: 2, sm: 3, md: 4 },
              mt: { xs: 10, sm: 10 },
              ml: { xs: 0, md: sidebarOpen ? '280px' : '0px' },
              transition: 'margin-left 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
              background: (theme) => 
                theme.palette.mode === 'dark'
                  ? 'radial-gradient(ellipse at top, rgba(139, 92, 246, 0.03) 0%, transparent 50%), linear-gradient(180deg, #0F0F23 0%, #1A1B3A 100%)'
                  : 'radial-gradient(ellipse at top, rgba(124, 58, 237, 0.02) 0%, transparent 50%), linear-gradient(180deg, #FAFBFC 0%, #FFFFFF 100%)',
              minHeight: '100vh',
              position: 'relative',
              maxWidth: '100%',
              overflow: 'hidden',
              '&::before': {
                content: '""',
                position: 'fixed',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                background: theme.palette.mode === 'dark'
                  ? 'radial-gradient(circle at 20% 80%, rgba(139, 92, 246, 0.05) 0%, transparent 50%), radial-gradient(circle at 80% 20%, rgba(236, 72, 153, 0.05) 0%, transparent 50%)'
                  : 'radial-gradient(circle at 20% 80%, rgba(124, 58, 237, 0.02) 0%, transparent 50%), radial-gradient(circle at 80% 20%, rgba(219, 39, 119, 0.02) 0%, transparent 50%)',
                pointerEvents: 'none',
                zIndex: -1,
              },
            }}
          >
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/analysis" element={<PostureAnalysis />} />
              <Route path="/risk" element={<RiskAssessment />} />
              <Route path="/rehabilitation" element={<Rehabilitation />} />
              <Route path="/settings" element={<Settings />} />
            </Routes>
          </Box>
        </Box>
      </Router>
    </ThemeProvider>
  );
};

export default App;
